<form method="POST" action="{{ $action }}" class="grid gap-4 md:grid-cols-2">@csrf @if(isset($unit)) @method('PUT') @endif <x-input name="name" label="Nome" value="{{ old('name', $unit->name ?? '') }}" required/><x-input name="code" label="Código" value="{{ old('code', $unit->code ?? '') }}"/><div><x-select name="type" label="Tipo" required>@foreach(['empresa','órgão','filial','secretaria','escola','setor','departamento','unidade_administrativa'] as $type)<option value="{{ $type }}" @selected(old('type', $unit->type ?? '') === $type)>{{ ucfirst(str_replace('_', ' ', $type)) }}</option>@endforeach</x-select></div><div><x-select name="status" label="Status" required><option value="active" @selected(old('status', $unit->status ?? '') === 'active')>Ativa</option><option value="inactive" @selected(old('status', $unit->status ?? '') === 'inactive')>Inativa</option></x-select></div><div class="md:col-span-2"><x-select name="parent_id" label="Unidade superior"><option value="">Sem unidade superior</option>@foreach($parents as $parent)<option value="{{ $parent->public_id }}" @selected(old('parent_id', $unit?->parent?->public_id ?? '') === $parent->public_id)>{{ $parent->name }}</option>@endforeach</x-select></div><div class="md:col-span-2"><x-button>{{ isset($unit) ? 'Salvar alterações' : 'Cadastrar unidade' }}</x-button></div></form>
